INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Dynamic_Back_Stretch','Dynamic Back Stretch','dorsales',ARRAY[]::text[],NULL,'stretching',ARRAY['Stand with your feet shoulder width apart. This will be your starting position.','Keeping your arms straight, swing them straight up in front of you 5-10 times, increasing the range of motion each time until your arms are above your head.'],'Stand with your feet shoulder width apart. This will be your starting position. Keeping your arms straight, swing them straight up in front of you 5-10 times, increasing the range of motion each time until your arms are above your head.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dynamic_Back_Stretch/0.jpg','exercisedb',true),('Dynamic_Chest_Stretch','Dynamic Chest Stretch','pecho',ARRAY['espalda media'],NULL,'stretching',ARRAY['Stand with your hands together, arms extended directly in front of you. This will be your starting position.','Keeping your arms straight, quickly move your arms back as far as possible and back in again, similar to an exaggerated clapping motion. Repeat 5-10 times, increasing speed as you do so.'],'Stand with your hands together, arms extended directly in front of you. This will be your starting position. Keeping your arms straight, quickly move your arms back as far as possible and back in again, similar to an exaggerated clapping motion. Repeat 5-10 times, increasing speed as you do so.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dynamic_Chest_Stretch/0.jpg','exercisedb',true),('EZ-Bar_Curl','EZ-Bar Curl','bíceps',ARRAY[]::text[],'barra curl EZ','strength',ARRAY['Stand up straight while holding an EZ curl bar at the wide outer handle. The palms of your hands should be facing forward and slightly tilted inward due to the shape of the bar. Keep your elbows close to your torso. This will be your starting position.','Now, while keeping your upper arms stationary, exhale and curl the weights forward while contracting the biceps. Focus on only moving your forearms.','Continue to raise the weight until your biceps are fully contracted and the bar is at shoulder level. Hold the top contracted position for a moment and squeeze the biceps.','Then inhale and slowly lower the bar back to the starting position.','Repeat for the recommended amount of repetitions.'],'Stand up straight while holding an EZ curl bar at the wide outer handle. The palms of your hands should be facing forward and slightly tilted inward due to the shape of the bar. Keep your elbows close to your torso. This will be your starting position. Now, while keeping your upper arms stationary, exhale and curl the weights forward while contracting the biceps. Focus on only moving your forearms. Continue to raise the weight until your biceps are fully contracted and the bar is at shoulder level. Hold the top contracted position for a moment and squeeze the biceps. Then inhale and slowly lower the bar back to the starting position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/EZ-Bar_Curl/0.jpg','exercisedb',true),('EZ-Bar_Skullcrusher','EZ-Bar Skullcrusher','tríceps',ARRAY['antebrazos'],'barra curl EZ','strength',ARRAY['Using a close grip, lift the EZ bar and hold it with your elbows in as you lie on the bench. Your arms should be perpendicular to the floor. This will be your starting position.','Keeping the upper arms stationary, lower the bar by allowing the elbows to flex. Inhale as you perform this portion of the movement. Pause once the bar is directly above the forehead.','Lift the bar back to the starting position by extending the elbow and exhaling.','Repeat.'],'Using a close grip, lift the EZ bar and hold it with your elbows in as you lie on the bench. Your arms should be perpendicular to the floor. This will be your starting position. Keeping the upper arms stationary, lower the bar by allowing the elbows to flex. Inhale as you perform this portion of the movement. Pause once the bar is directly above the forehead. Lift the bar back to the starting position by extending the elbow and exhaling. Repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/EZ-Bar_Skullcrusher/0.jpg','exercisedb',true),('Elbow_Circles','Elbow Circles','hombros',ARRAY['trapecios'],NULL,'stretching',ARRAY['Sit or stand with your feet slightly apart.','Place your hands on your shoulders with your elbows at shoulder level and pointing out.','Slowly make a circle with your elbows. Breathe out as you start the circle and breathe in as you complete the circle.'],'Sit or stand with your feet slightly apart. Place your hands on your shoulders with your elbows at shoulder level and pointing out. Slowly make a circle with your elbows. Breathe out as you start the circle and breathe in as you complete the circle.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elbow_Circles/0.jpg','exercisedb',true),('Elbow_to_Knee','Elbow to Knee','abdominales',ARRAY[]::text[],'peso corporal','strength',ARRAY['Lie on the floor, crossing your right leg across your bent left knee. Clasp your hands behind your head, beginning with your shoulder blades on the ground. This will be your starting position.','Perform the motion by flexing the spine and rotating your torso to bring the left elbow to the right knee.','Return to the starting position and repeat the movement for the desired number of repetitions before switching sides.'],'Lie on the floor, crossing your right leg across your bent left knee. Clasp your hands behind your head, beginning with your shoulder blades on the ground. This will be your starting position. Perform the motion by flexing the spine and rotating your torso to bring the left elbow to the right knee. Return to the starting position and repeat the movement for the desired number of repetitions before switching sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elbow_to_Knee/0.jpg','exercisedb',true),('Elbows_Back','Elbows Back','pecho',ARRAY['hombros'],NULL,'stretching',ARRAY['Stand up straight.','Place both hands on your lower back, fingers pointing downward and elbows out.','Then gently pull your elbows back aiming to touch them together.'],'Stand up straight. Place both hands on your lower back, fingers pointing downward and elbows out. Then gently pull your elbows back aiming to touch them together.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elbows_Back/0.jpg','exercisedb',true),('Elevated_Back_Lunge','Elevated Back Lunge','cuádriceps',ARRAY['glúteos','isquiotibiales'],'barra','strength',ARRAY['Position a bar onto a rack at shoulder height loaded to an appropriate weight. Place a short, raised platform behind you.','Rack the bar onto your upper back, keeping your back arched and tight. Step onto your raised platform with both feet. This will be your starting position.','Begin by stepping backwards with one leg. Descend by flexing your hips and knees until your knee touches the floor.','Pause, and extend through the hips and knees to rise up, returning all the way to the starting position before alternating.'],'Position a bar onto a rack at shoulder height loaded to an appropriate weight. Place a short, raised platform behind you. Rack the bar onto your upper back, keeping your back arched and tight. Step onto your raised platform with both feet. This will be your starting position. Begin by stepping backwards with one leg. Descend by flexing your hips and knees until your knee touches the floor. Pause, and extend through the hips and knees to rise up, returning all the way to the starting position before alternating.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elevated_Back_Lunge/0.jpg','exercisedb',true),('Elevated_Cable_Rows','Elevated Cable Rows','dorsales',ARRAY['espalda media','trapecios'],'cable','strength',ARRAY['Get a platform of some sort (it can be an aerobics or calf raise platform) that is around 4-6 inches in height.','Place it on the seat of the cable row machine.','Sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.','Lean over as you keep the natural alignment of your back and grab the V-bar handles.','With your arms extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lats as you hold the bar in front of you. This is the starting position of the exercise.','Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it until you touch the abdominals. Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in.','Repeat for the recommended amount of repetitions.'],'Get a platform of some sort (it can be an aerobics or calf raise platform) that is around 4-6 inches in height. Place it on the seat of the cable row machine. Sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked. Lean over as you keep the natural alignment of your back and grab the V-bar handles. With your arms extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lats as you hold the bar in front of you. This is the starting position of the exercise. Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it until you touch the abdominals. Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elevated_Cable_Rows/0.jpg','exercisedb',true),('Elliptical_Trainer','Elliptical Trainer','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'máquina','cardio',ARRAY['To begin, step onto the elliptical and select the desired option from the menu. Most ellipticals have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.','The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.'],'To begin, step onto the elliptical and select the desired option from the menu. Most ellipticals have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elliptical_Trainer/0.jpg','exercisedb',true);